Here's a simple Python program that stores information about users in a dictionary and allows you to add, delete, and display users:
```python
class User:
    def __init__(self, name, email):
        self.name = name
        self.email = email

class JohnsonSystem:
    def __init__(self):
        self.users = {}

    def add_user(self, name, email):
        if name in self.users:
            print("User already exists")
        else:
            self.users[name] = User(name, email)
            print(f"User {name} added successfully")

    def delete_user(self, name):
        if name not in self.users:
            print("User does not exist")
        else:
            del self.users[name]
            print(f"User {name} deleted successfully")

    def display_users(self):
        if len(self.users) == 0:
            print("No users available")
        else:
            for user in self.users.values():
                print(f"Name: {user.name}, Email: {user.email}")

def main():
    johnson_system = JohnsonSystem()

    while True:
        print("\n1. Add User")
        print("2. Delete User")
        print("3. Display Users")
        print("4. Exit")

        choice = input("Choose an option: ")

        if choice == "1":
            name = input("Enter user's name: ")
            email = input("Enter user's email: ")
            johnson_system.add_user(name, email)
        elif choice == "2":
            name = input("Enter user's name to delete: ")
            johnson_system.delete_user(name)
        elif choice == "3":
            johnson_system.display_users()
        elif choice == "4":
            print("Exiting the system")
            break
        else:
            print("Invalid option")

if __name__ == "__main__":
    main()
```
This program creates a simple text-based interface to interact with the `JohnsonSystem` class. It allows you to add, delete, and display users. The user information is stored in a dictionary where the key is the username and the value is an instance of the `User` class.

You can run this code in your Python environment to test it out!
